// REGLA 1: NORMALIZACIÓN DE TIPOS
// REGLA 5: VALIDACIÓN DE PAYLOAD
const raw = $input.first()?.json || {};
// Handle both webhook (raw.body) and execute workflow (raw directly)
const input = Object.keys(raw.body || {}).length > 0 ? raw.body : raw;

// Normalizar tipos (REGLA 1)
const provider_id = Number(input.provider_id ?? 1);
const service_id = Number(input.service_id ?? 1);
let date = String(input.date || "");

// Evitar que lea la versión 1.3.0 por accidente u otro metadato
if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
  date = new Date().toISOString().split('T')[0];
}

// Validar payload (REGLA 5)
const isValidProvider = provider_id > 0 && Number.isInteger(provider_id);
const isValidService = service_id > 0 && Number.isInteger(service_id);
const isValidDate = /^\d{4}-\d{2}-\d{2}$/.test(date);

const isValid = isValidProvider && isValidService && isValidDate;

return [{
  json: {
    provider_id,
    service_id,
    date,
    isValid,
    _meta: {
      source: 'DB_Get_Availability',
      timestamp: new Date().toISOString(),
      workflow_id: 'DB_Get_Availability',
      version: '1.3.1'
    }
  }
}];

return [{
  json: {
    success: false,
    error_code: "INVALID_AVAILABILITY_PARAMS",
    error_message: "Parámetros inválidos: provider_id y service_id deben ser números positivos, date debe ser YYYY-MM-DD",
    data: null,
    _meta: {
      source: 'DB_Get_Availability',
      timestamp: new Date().toISOString(),
      workflow_id: 'DB_Get_Availability',
      version: '1.3.0'
    }
  }
}];

// Format availability response — Tool-compatible v3.1.0
const input = $input.first()?.json || {};
const isCacheHit   = input.cache_hit === true;
const dalResponse  = isCacheHit ? input.cache_data : input;
const isSuccess    = dalResponse.success !== false;
const slots        = dalResponse.data?.available_slots || dalResponse.data?.slots || [];
const hasSlots     = slots.length > 0;

let message;
if (!isSuccess) {
  message = dalResponse.error_message || 'Error consultando disponibilidad. Informa al usuario e invítalo a intentarlo en unos minutos.';
} else if (hasSlots) {
  message = `Hay ${slots.length} turno(s) disponible(s) para esa fecha. Muéstrale las opciones al usuario para que elija.`;
} else {
  message = 'NO HAY TURNOS DISPONIBLES para esa fecha. Instrucción: Informa al usuario y ofrécele SIEMPRE dos alternativas: (1) buscar el próximo turno disponible usando FindNextAvailable, (2) unirse a la lista de espera usando ManageWaitlist.';
}

return [{
  json: {
    success: isSuccess,
    message,
    error_code:    isSuccess ? null : (dalResponse.error_code    || 'DAL_ERROR'),
    error_message: isSuccess ? null : (dalResponse.error_message || 'Operation failed'),
    data: isSuccess ? { available_slots: slots } : null,
    _meta: { source: 'DB_Get_Availability', timestamp: new Date().toISOString(), version: '3.1.0' }
  }
}];

// 📤 STANDARD CONTRACT OUTPUT — Tool-compatible (v3.0.0)
// El AI Agent lee "message" como respuesta legible y "data" para detalles.
const result = $input.first()?.json || {};
const isSuccess = result.success !== false;

// Construir mensaje legible para el LLM
let message = result.message || result.data?.message || null;
if (!message) {
  message = isSuccess
    ? 'Operación completada con éxito.'
    : (result.error_message || result.error_code || 'Error desconocido.');
}

return [{
  json: {
    success: isSuccess,
    message,
    error_code:    isSuccess ? null : (result.error_code    || 'UNKNOWN_ERROR'),
    error_message: isSuccess ? null : (result.error_message || message),
    data:          result.data || null,
    _meta: {
      source:    'DB_GET_AVAILABILITY',
      timestamp: new Date().toISOString(),
      version:   '3.0.0'
    }
  }
}];
